{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "硬件攻坚：材料与传感架构构建",
      "description": "完成仿水膜-鱼网结构的液态金属基导电薄膜与低迟滞聚氨酯介质复合材料体系研发，实现0.1mm级空间分辨率。构建融合光纤传感与惯性测量单元（IMU）的混合传感架构，进行传感器微结构设计、材料复合工艺优化与信号标定。人员配置为硬件工程师2名、材料研究员1名，关键资源为柔性材料合成设备与高精度信号采集平台。"
    },
    {
      "date": "第3月",
      "title": "算法开发：分层模型与融合协议",
      "description": "开发轻量化手势识别分层模型，结合时序滑动窗口分割与噪声抑制模块，实现毫秒级实时推理，实测复杂工况下识别准确率>98.2%。开发基于统一时空对齐协议的多模态融合引擎，支持视觉-触觉-听觉数据低延迟融合。人员配置为算法工程师3名、数据标注员1名，关键资源为GPU服务器（4×A100）、标注数据集与仿真环境。"
    },
    {
      "date": "第4月",
      "title": "系统集成：软硬件联调与反馈嵌入",
      "description": "集成多模态交互协议栈，嵌入微型电磁致动器阵列与半导体温控模块构成的触觉反馈执行单元，实现压力/温度参数的微秒级精准调控。完成软硬件联调，构建感知-意图-反馈闭环。人员配置为全栈工程师2名、测试工程师2名，关键资源为多模态测试舱及合作设备接口（如H-Box全息舱）。"
    },
    {
      "date": "第5–6月",
      "title": "场景验证优化：多场景测试与迭代",
      "description": "依托合作企业平台（H-Box全息舱、李未可眼镜等）开展工业级远程操控、虚拟实训等多场景压力测试。收集用户体验反馈进行迭代优化，形成可复用的交互标准接口，开发效率提升60%。人员配置为产品经理1名、场景测试员2名，关键资源为远程操控实训场地与用户反馈采集系统。"
    }
  ]
}

